#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    int c=getchar(); // consume newline after T
    char buf[1005];
    while(T--){
        if(!fgets(buf, sizeof(buf), stdin)) break;
        size_t len=strlen(buf);
        if(len>0 && buf[len-1]=='\n') buf[--len]='\0';
        if(len>0) printf("%c\n", buf[len-1]);
    }
    return 0;
}

