import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        s = data[i]
        out.append(s[-1])
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

